import { useState } from "react";
import axios from "axios";
import Api from "../api/Api";
import { useNavigate } from "react-router-dom";

function LoginPage() {

  const [mobile, setMobile] =
    useState("");

  const navigate =
    useNavigate();

  const handleSendOtp =
    async (e) => {

      e.preventDefault();

      try {

        const res =
          await axios.post(
            Api.send_otp,
            { mobile }
          );

        alert(res.data.message);

        navigate(
          "/verify-otp",
          {
            state: { mobile }
          }
        );

      } catch (err) {

        alert(
          err.response?.data
            ?.message
        );

      }
    };

  return (
    <div>

      <form
        onSubmit={
          handleSendOtp
        }
      >

        <input
          value={mobile}
          onChange={(e) =>
            setMobile(
              e.target.value
            )
          }
          placeholder="Mobile Number"
        />

        <button>
          Send OTP
        </button>

      </form>

    </div>
  );
}

export default LoginPage;
